"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Globe, Scale, BarChart3, LayoutDashboard, PieChart } from "lucide-react";

const navItems = [
  { href: "/dashboard", label: "대시보드", icon: LayoutDashboard },
  { href: "/issues", label: "국내외뉴스", icon: Globe },
  { href: "/policy", label: "정책돋보기", icon: Scale },
  { href: "/stock", label: "AI종목분석", icon: BarChart3 },
  { href: "/portfolio", label: "내 포트폴리오", icon: PieChart },
];

export default function NavBar() {
  const pathname = usePathname();

  return (
    <nav className="sticky top-0 z-50 bg-navy/90 backdrop-blur-md border-b border-white/10">
      <div className="max-w-5xl mx-auto px-4 h-14 flex items-center justify-between">
        <Link href="/" className="text-xl font-bold text-sky-400 tracking-tight">
          주식콕
        </Link>

        <div className="flex items-center gap-1">
          {navItems.map(({ href, label, icon: Icon }) => {
            const active = pathname.startsWith(href);
            return (
              <Link
                key={href}
                href={href}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-colors ${
                  active
                    ? "bg-skyblue/20 text-skyblue"
                    : "text-gray-400 hover:text-white hover:bg-white/5"
                }`}
              >
                <Icon className="w-4 h-4" />
                <span className="hidden sm:inline">{label}</span>
              </Link>
            );
          })}
        </div>
      </div>
    </nav>
  );
}
